/* Arumed Apps design tokens
 * Single source of truth for colors, spacing, and surfaces.
 * Mirrors the palette established across the static HTML prototypes. */

:root {
  /* Brand (primary) — tema biru Prima Vision (selaras logo: navy iris + cross cyan) */
  --gd: #0f2d56;
  --gm: #1554a0;
  --ga: #1763d4;
  --gl: #eaf2fb;
  --gb: #cbdcf0;

  /* Accent — cyan terang dari mata/cross logo */
  --lm: #3fb5e8;
  --ld: #0284c7;

  /* Backgrounds & surfaces — cool slate (premium hospital, tanpa nuansa hijau) */
  --bg: #f4f7fb;
  --bp: #f7fafd;
  --bc: #ffffff;
  --bs: #f8fbfe;
  --bi: #f4f8fc;

  /* Text — slate-navy, kontras tinggi & bersih */
  --td: #0f1f33;
  --tm: #42526b;
  --tu: #64748b;
  --th: #94a3b8;

  /* Semantic — success */
  --sb: #f0fdf4;
  --sbd: #86efac;
  --st: #15803d;

  /* Semantic — error */
  --eb: #fef2f2;
  --ebd: #fca5a5;
  --et: #dc2626;

  /* Semantic — warning */
  --wb: #fffbeb;
  --wbd: #fcd34d;
  --wt: #b45309;

  /* Semantic — info */
  --ib: #eff6ff;
  --ibd: #93c5fd;
  --it: #1d4ed8;

  /* Semantic — purple (ASN/special) */
  --pb: #fdf4ff;
  --pbd: #d946ef;
  --pt: #7e22ce;

  /* Layout */
  --sidebar: 240px;
}

