:root {
  /* Brand (primary) — Clinical White: navy untuk teks/header, biru sbg AKSEN saja */
  --gd: #12386b;   /* navy — judul, header, ikon brand */
  --gm: #1554a0;   /* navy-biru sedang */
  --ga: #1763d4;   /* AKSEN biru — tombol, link, state aktif */
  --gl: #eef4fc;   /* tint biru sangat muda — bg item aktif/hover */
  --gb: #e6ebf2;   /* border netral cool-grey (clean) */

  /* Accent — cyan terang dari mata/cross logo (highlight kecil) */
  --lm: #3fb5e8;
  --ld: #0284c7;

  /* Backgrounds & surfaces — putih dominan, abu cool sangat tipis (paling clean) */
  --bg: #f7f9fc;   /* page bg — abu-cool nyaris putih */
  --bp: #fbfcfe;   /* panel */
  --bc: #ffffff;   /* kartu/surface utama — putih bersih */
  --bs: #f9fbfe;   /* surface lembut */
  --bi: #f5f8fc;   /* surface info/zebra */

  /* Text — navy untuk heading, slate untuk body/muted (kontras tinggi, bersih) */
  --td: #0f1f33;   /* teks utama / heading (navy) */
  --tm: #45556c;   /* teks sekunder (slate-600) */
  --tu: #64748b;   /* muted (slate-500, aksesibel) */
  --th: #94a3b8;   /* hint (slate-400) */

  /* Semantic — success */
  --sb: #f0fdf4;
  --sbd: #86efac;
  --st: #15803d;

  /* Semantic — error */
  --eb: #fef2f2;
  --ebd: #fca5a5;
  --et: #dc2626;

  /* Semantic — warning */
  --wb: #fffbeb;
  --wbd: #fcd34d;
  --wt: #b45309;

  /* Semantic — info */
  --ib: #eff6ff;
  --ibd: #93c5fd;
  --it: #1d4ed8;

  /* Semantic — purple (ASN/special) */
  --pb: #fdf4ff;
  --pbd: #d946ef;
  --pt: #7e22ce;

  /* Layout */
  --sidebar: 240px;

