  --font-sans: 'Inter', system-ui, -apple-system, 'Segoe UI', sans-serif;
  --font-display: 'Space Grotesk', 'Inter', system-ui, sans-serif;
  --font-mono: 'JetBrains Mono', 'SF Mono', 'Consolas', monospace;
}

/* Arumed Apps design tokens
 * Single source of truth for colors, spacing, and surfaces.
 * Mirrors the palette established across the static HTML prototypes. */

:root {
  /* Brand (primary) — navy-premium: biru DITAHAN (hemat), navy untuk struktur */
  --gd: #103a68;   /* navy pekat — judul, header, btn-primary (mahal, institusional) */
  --gm: #18548f;   /* navy sedang — hover */
  --ga: #1d63b3;   /* AKSEN biru (lebih dalam & kalem, tidak ngejreng) — tombol/link/aktif */
  --gl: #eef3f9;   /* tint sangat halus — bg item aktif/hover (tidak 'menyala') */
  --gb: #e3e7ee;   /* border halus abu-biru netral */

  /* Accent — cyan logo (highlight kecil saja, jangan dominan) */
  --lm: #3fb5e8;
  --ld: #0284c7;

  /* Backgrounds & surfaces — putih bersih + abu netral lembut (premium, tidak dingin) */
  --bg: #f6f8fb;   /* page bg — abu-cool nyaris putih */
  --bp: #fbfcfe;   /* panel */
  --bc: #ffffff;   /* kartu/surface utama — putih bersih */
  --bs: #f9fafc;   /* surface lembut */
  --bi: #f3f5f8;   /* surface info / baris zebra (abu netral lembut) */

  /* Text — navy untuk heading, slate untuk body/muted (kontras tinggi, bersih) */
  --td: #0f1f33;   /* teks utama / heading (navy) */
  --tm: #45556c;   /* teks sekunder (slate-600) */
  --tu: #64748b;   /* muted (slate-500, aksesibel) */
  --th: #94a3b8;   /* hint (slate-400) */

  /* Semantic — success */
  --sb: #f0fdf4;
  --sbd: #86efac;
  --st: #15803d;

  /* Semantic — error */
  --eb: #fef2f2;
  --ebd: #fca5a5;
  --et: #dc2626;

  /* Semantic — warning */
  --wb: #fffbeb;
  --wbd: #fcd34d;
  --wt: #b45309;

  /* Semantic — info */
  --ib: #eff6ff;
  --ibd: #93c5fd;
  --it: #1d4ed8;

  /* Semantic — purple (ASN/special) */
  --pb: #fdf4ff;
  --pbd: #d946ef;
  --pt: #7e22ce;

  /* Layout */
  --sidebar: 240px;

  /* Typography — Inter (body/UI) + Space Grotesk (heading kontras) + JetBrains Mono */
  --font-sans: 'Inter', system-ui, -apple-system, 'Segoe UI', sans-serif;
  --font-display: 'Space Grotesk', 'Inter', system-ui, sans-serif;
  --font-mono: 'JetBrains Mono', 'SF Mono', 'Consolas', monospace;
}

