}

/* LEFT PANEL */
.lp {
  width: 46%;
  background: var(--gd);
  position: relative;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: space-between;
  padding: 3rem 2.5rem;
  overflow: hidden;
}
.ring {
  position: absolute;
  border-radius: 50%;
  pointer-events: none;
  border: 1px solid rgba(56, 189, 248, 0.11);
}
.logo-area {
  display: flex;
  flex-direction: column;
  align-items: center;
  position: relative;
  z-index: 2;
}
.eye-wrap {
  position: relative;
  width: 92px;
  height: 92px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 1.25rem;
}
.ripple {
  position: absolute;
  inset: 0;
  border-radius: 50%;
  border: 1px solid rgba(56, 189, 248, 0.4);
}
.r1 { animation: ripple 3s ease-out infinite; }
.r2 { animation: ripple 3s ease-out 1s infinite; }
.r3 { animation: ripple 3s ease-out 2s infinite; }
.brand-sub {
  font-size: 10px;
  letter-spacing: 0.3em;
  color: var(--lm);
  text-transform: uppercase;

:root {
  /* Brand (primary) — navy-premium: biru DITAHAN (hemat), navy untuk struktur */
  --gd: #103a68;   /* navy pekat — judul, header, btn-primary (mahal, institusional) */
  --gm: #18548f;   /* navy sedang — hover */
  --ga: #1d63b3;   /* AKSEN biru (lebih dalam & kalem, tidak ngejreng) — tombol/link/aktif */
  --gl: #eef3f9;   /* tint sangat halus — bg item aktif/hover (tidak 'menyala') */
  --gb: #e3e7ee;   /* border halus abu-biru netral */

  /* Accent — cyan logo (highlight kecil saja, jangan dominan) */
  --lm: #3fb5e8;
  --ld: #0284c7;

  /* Backgrounds & surfaces — putih bersih + abu netral lembut (premium, tidak dingin) */
  --bg: #f6f8fb;   /* page bg — abu-cool nyaris putih */
  --bp: #fbfcfe;   /* panel */
  --bc: #ffffff;   /* kartu/surface utama — putih bersih */
  --bs: #f9fafc;   /* surface lembut */
  --bi: #f3f5f8;   /* surface info / baris zebra (abu netral lembut) */

  /* Text — hitam/abu NETRAL (tanpa undertone biru), kontras tinggi & bersih */
  --td: #1a1a1a;   /* teks utama / judul — hitam pekat */
  --tm: #333333;   /* teks sekunder — abu-hitam */
  --tu: #6b7280;   /* muted — abu netral (aksesibel) */
  --th: #9ca3af;   /* hint — abu netral terang */

  /* Semantic — success */
  --sb: #f0fdf4;
  --sbd: #86efac;
  --st: #15803d;

